({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  // Check for existing session on mount
  useEffect(() => {
    const checkSession = async () => {
      try {
        const response = await api.post('/auth/refresh');
        const { accessToken } = response.data;
        setAccessToken(accessToken);
        
        const storedUser = localStorage.getItem('erkata_user');
        if (storedUser) {
          setUser(JSON.parse(storedUser));
        }
      } catch (e) {
        localStorage.removeItem('erkata_user');
        setAccessToken('');
      } finally {
        setIsLoading(false);
      }
    };

    checkSession();
  }, []);

  const login = async (email: string, password: string): Promise<boolean> => {
    try {
      const response = await api.post('/auth/login', { email, password });
      const { user: userData, accessToken } = response.data;
      
      setAccessToken(accessToken);

      const authenticatedUser: User = {
        id: userData.id,
        email: userData.email,
        role: normalizeRole(userData.role),
        name: userData.fullName,
      };

      setUser(authenticatedUser);
      localStorage.setItem('erkata_user', JSON.stringify(authenticatedUser));
      return true;
    } catch (error) {
      console.error('Login failed:', error);
      return false;
    }
  };

  const logout = async () => {
    try {
      await api.post('/auth/logout');
    } finally {
      setUser(null);
      setAccessToken('');
      localStorage.removeItem('erkata_user');
    }
  };

  const signup = async (data: { fullName: string; email: string; phone: string; password: string; role: string }) => {
    try {
      const payload = {
        ...data,
        role: denormalizeRole(data.role),
      };
      const response = await api.post('/auth/register', payload);
      const { user: userData, accessToken } = response.data;

      setAccessToken(accessToken || '');

      const newUser: User = { 
        id: userData.id,
        name: userData.fullName, 
        email: userData.email, 
        role: normalizeRole(userData.role) 
      };
      
      setUser(newUser);
      localStorage.setItem('erkata_user', JSON.stringify(newUser));
    } catch (error) {
      console.error('Registration failed:', error);
      throw error;
    }
  };

  return (
    <AuthContext.Provider value={{ user, login, logout, signup, isAuthenticated: !!user, isLoading }}>
      {!isLoading && children}
    </AuthContext.Provider>
  );
}

