({ children, allowedRole }) => {
  const { user, isAuthenticated, isLoading } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    if (!isLoading) {
      if (!isAuthenticated) {
        navigate('/login', { replace: true });
      } else if (user?.role !== allowedRole) {
        // Redirect to correct dashboard based on role
        let correctPath = '/login';
        if (user?.role === 'agent') correctPath = '/agent-dashboard';
        if (user?.role === 'operator') correctPath = '/operator-dashboard';
        if (user?.role === 'admin') correctPath = '/admin-dashboard';
        if (user?.role === 'super-admin') correctPath = '/superadmin';
        if (user?.role === 'customer') correctPath = '/customer';
        
        navigate(correctPath, { replace: true });
      }
    }
  }, [isLoading, isAuthenticated, user, allowedRole, navigate]);

  if (isLoading || !isAuthenticated || user?.role !== allowedRole) {
    return null;
  }

  return <>{children}</>;
}

